/**
 * MedX section layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Page section spacing and titles.
 */
const SECTION_TOKENS = Object.freeze({
  primary: { value: "layout-section-primary", scope: "layout" },
  secondary: { value: "layout-section-secondary", scope: "layout" },
  muted: { value: "layout-section-muted", scope: "layout" },
  accent: { value: "layout-section-accent", scope: "layout" },
  surface: { value: "layout-section-surface", scope: "layout" },
});

const SECTION_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SECTION_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const sectionRegistry = new Map();
const SECTION_listeners = new Set();
let SECTION_seq = 0;

function createSectionId(prefix = "medx-layout-section") {
  SECTION_seq += 1;
  return `${prefix}-${SECTION_seq}`;
}

function registerSection(config = {}) {
  const entryId = config.id ?? createSectionId();
  const preset = SECTION_PRESETS[config.preset ?? "default"] ?? SECTION_PRESETS.default;
  const token = SECTION_TOKENS[config.token ?? preset.token] ?? SECTION_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SECTION_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  sectionRegistry.set(entryId, entry);
  notifySectionListeners("register", entry);
  return entry;
}

function updateSection(id, patch = {}) {
  const entry = sectionRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySectionListeners("update", entry);
  return entry;
}

function resolveSection(id) {
  const entry = sectionRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSectionEntries(filter = {}) {
  let items = Array.from(sectionRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSectionEvent(listener) {
  SECTION_listeners.add(listener);
  return () => SECTION_listeners.delete(listener);
}

function notifySectionListeners(type, entry) {
  for (const listener of SECTION_listeners) {
    try {
      listener({ type, entry, registrySize: sectionRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:section] listener error", err.message);
    }
  }
}

function getSectionMetrics() {
  const items = listSectionEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SECTION_TOKENS).length,
    presets: Object.keys(SECTION_PRESETS).length,
  };
}

async function runMedxSection() {
  console.log("[medx:ui:layout:section] runtime initialized");
  console.log(`[medx:ui:layout:section] tokens=${Object.keys(SECTION_TOKENS).length} presets=${Object.keys(SECTION_PRESETS).length}`);

  const events = [];
  onSectionEvent((e) => events.push(e.type));

  const domains = Object.keys(SECTION_SUPPLY_CHAIN);
  const presets = Object.keys(SECTION_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSection({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/section" },
    });
  }

  const first = listSectionEntries()[0];
  if (first) updateSection(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSectionMetrics();
  const resolved = first ? resolveSection(first.id) : null;

  console.log(`[medx:ui:layout:section] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:section] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:section] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:section] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:section] bootstrap complete");
}

module.exports = runMedxSection;
